using Solutions;
using Xunit;

namespace Tests
{
    public class TestDay19
    {
        [Fact]
        public void Part1()
        {
            var day19 = new Day19();
            var actual = day19.Walk(@"     |          
     |  +--+    
     A  |  C    
 F---|----E|--+ 
     |  |  |  D 
     +B-+  +--+ 
");
            Assert.Equal("ABCDEF", actual);
        }

        [Fact]
        public void Part1_Answer()
        {
            var day19 = new Day19();
            var actual = day19.Walk(PUZZLE_INPUT);
            Assert.Equal("ABCDEF", actual);
        }

